(() => {
  const logradouro = $json["logradouro"] || "";
  const numero = $json["numero"] || "";
  const complemento = $json["complemento"] ? " - " + $json["complemento"] : "";
  const bairro = $json["bairro"] || "";
  const municipio = $json["municipio"] || "";
  const uf = ($json["uf"] || "").toUpperCase();
  const cep = ($json["cep"] || "").replace(/\D/g, "").replace(/(\d{5})(\d{3})/, "$1-$2");

  // Função para colocar a primeira letra de cada palavra em maiúscula
  const titleCase = (str) =>
    str
      .toLowerCase()
      .replace(/\b[a-zà-ú]/gi, (c) => c.toUpperCase());

  return `${titleCase(logradouro)}, ${numero}${complemento}, ${titleCase(bairro)}, ${titleCase(municipio)}, ${uf}, ${cep}`;
})()
}}

